 1→import { Injectable, Logger } from '@nestjs/common';
 2→import { Cron } from '@nestjs/schedule';
 3→import { InjectRepository } from '@nestjs/typeorm';
 4→import { Repository, LessThan } from 'typeorm';
 5→import { Session } from '../auth/session.entity';
 6→import { LoginAttempt } from '../auth/login-attempt.entity';
 7→import { PowChallenge } from '../auth/pow-challenge.entity';
 8→import { IdempotencyService } from '../idempotency/idempotency.service';
 9→
10→@Injectable()
11→export class CleanupJob {
12→  private readonly logger = new Logger(CleanupJob.name);
13→
14→  constructor(
15→    @InjectRepository(Session)
16→    private sessionRepo: Repository<Session>,
17→    @InjectRepository(LoginAttempt)
18→    private loginAttemptRepo: Repository<LoginAttempt>,
19→    @InjectRepository(PowChallenge)
20→    private powRepo: Repository<PowChallenge>,
21→    private idempotencyService: IdempotencyService,
22→  ) {}
23→
24→  @Cron('0 * * * *') // Every hour — session cleanup
25→  async cleanupSessions(): Promise<void> {
26→    const now = new Date();
27→    const result = await this.sessionRepo.delete({
28→      expiresAt: LessThan(now),
29→    });
30→    this.logger.log(`Cleaned ${result.affected} expired sessions`);
31→  }
32→
33→  @Cron('0 * * * *') // Every hour — login attempt cleanup
34→  async cleanupLoginAttempts(): Promise<void> {
35→    const cutoff = new Date(Date.now() - 24 * 60 * 60 * 1000);
36→    const result = await this.loginAttemptRepo.delete({
37→      attemptedAt: LessThan(cutoff),
38→    });
39→    this.logger.log(`Cleaned ${result.affected} old login attempts`);
40→  }
41→
42→  @Cron('0 * * * *') // Every hour — PoW challenge cleanup
43→  async cleanupPowChallenges(): Promise<void> {
44→    const cutoff = new Date(Date.now() - 60 * 60 * 1000);
45→    const result = await this.powRepo.delete({
46→      expiresAt: LessThan(cutoff),
47→    });
48→    this.logger.log(`Cleaned ${result.affected} expired PoW challenges`);
49→  }
50→
51→  @Cron('0 */6 * * *') // Every 6 hours — idempotency key purge
52→  async purgeIdempotencyKeys(): Promise<void> {
53→    const purged = await this.idempotencyService.purgeExpired();
54→    this.logger.log(`Purged ${purged} expired idempotency keys`);
55→  }
56→}
