 1→import {
 2→  Injectable,
 3→  CanActivate,
 4→  ExecutionContext,
 5→  UnauthorizedException,
 6→} from '@nestjs/common';
 7→import { Reflector } from '@nestjs/core';
 8→import { InjectRepository } from '@nestjs/typeorm';
 9→import { Repository, MoreThan } from 'typeorm';
10→import { Session } from '../../auth/session.entity';
11→import { IS_PUBLIC_KEY } from '../decorators/public.decorator';
12→
13→@Injectable()
14→export class AuthGuard implements CanActivate {
15→  constructor(
16→    private reflector: Reflector,
17→    @InjectRepository(Session)
18→    private sessionRepo: Repository<Session>,
19→  ) {}
20→
21→  async canActivate(context: ExecutionContext): Promise<boolean> {
22→    const isPublic = this.reflector.getAllAndOverride<boolean>(IS_PUBLIC_KEY, [
23→      context.getHandler(),
24→      context.getClass(),
25→    ]);
26→    if (isPublic) return true;
27→
28→    const request = context.switchToHttp().getRequest();
29→    const authHeader = request.headers.authorization;
30→
31→    if (!authHeader || !authHeader.startsWith('Bearer ')) {
32→      throw new UnauthorizedException('Missing or invalid authorization header');
33→    }
34→
35→    const token = authHeader.slice(7);
36→    const session = await this.sessionRepo.findOne({
37→      where: {
38→        token,
39→        expiresAt: MoreThan(new Date()),
40→      },
41→      relations: ['user', 'user.userRoles', 'user.userRoles.role'],
42→    });
43→
44→    if (!session) {
45→      throw new UnauthorizedException('Invalid or expired session');
46→    }
47→
48→    if (!session.user.isActive) {
49→      throw new UnauthorizedException('Account is deactivated');
50→    }
51→
52→    request.user = session.user;
53→    request.sessionId = session.id;
54→
55→    return true;
56→  }
57→}
