 1→import {
 2→  Injectable,
 3→  CanActivate,
 4→  ExecutionContext,
 5→  HttpException,
 6→  HttpStatus,
 7→} from '@nestjs/common';
 8→import { AppConfigService } from '../../config/config.service';
 9→
10→interface RateLimitEntry {
11→  timestamps: number[];
12→}
13→
14→@Injectable()
15→export class RateLimitGuard implements CanActivate {
16→  private readonly store = new Map<string, RateLimitEntry>();
17→
18→  constructor(private config: AppConfigService) {}
19→
20→  canActivate(context: ExecutionContext): boolean {
21→    const request = context.switchToHttp().getRequest();
22→    const ip = request.ip || request.connection?.remoteAddress || 'unknown';
23→    const now = Date.now();
24→    const windowMs = this.config.loginRateLimitWindowMs;
25→    const max = this.config.loginRateLimitMax;
26→
27→    let entry = this.store.get(ip);
28→    if (!entry) {
29→      entry = { timestamps: [] };
30→      this.store.set(ip, entry);
31→    }
32→
33→    // Sliding window: remove entries outside the window
34→    entry.timestamps = entry.timestamps.filter((t) => now - t < windowMs);
35→
36→    if (entry.timestamps.length >= max) {
37→      const oldestInWindow = entry.timestamps[0];
38→      const retryAfterMs = windowMs - (now - oldestInWindow);
39→      const retryAfterSec = Math.ceil(retryAfterMs / 1000);
40→
41→      throw new HttpException(
42→        {
43→          statusCode: HttpStatus.TOO_MANY_REQUESTS,
44→          error: 'Too Many Requests',
45→          message: `Rate limit exceeded. Try again in ${retryAfterSec} seconds.`,
46→          retryAfter: retryAfterSec,
47→        },
48→        HttpStatus.TOO_MANY_REQUESTS,
49→      );
50→    }
51→
52→    entry.timestamps.push(now);
53→    return true;
54→  }
55→
56→  /** Visible for testing */
57→  clearStore(): void {
58→    this.store.clear();
59→  }
60→
61→  getAttemptCount(ip: string): number {
62→    const entry = this.store.get(ip);
63→    if (!entry) return 0;
64→    const now = Date.now();
65→    const windowMs = this.config.loginRateLimitWindowMs;
66→    return entry.timestamps.filter((t) => now - t < windowMs).length;
67→  }
68→}
