 1→import {
 2→  Injectable,
 3→  CanActivate,
 4→  ExecutionContext,
 5→  ForbiddenException,
 6→} from '@nestjs/common';
 7→import { Reflector } from '@nestjs/core';
 8→import { ROLES_KEY } from '../decorators/roles.decorator';
 9→
10→@Injectable()
11→export class RolesGuard implements CanActivate {
12→  constructor(private reflector: Reflector) {}
13→
14→  canActivate(context: ExecutionContext): boolean {
15→    const requiredRoles = this.reflector.getAllAndOverride<string[]>(ROLES_KEY, [
16→      context.getHandler(),
17→      context.getClass(),
18→    ]);
19→    if (!requiredRoles || requiredRoles.length === 0) {
20→      return true;
21→    }
22→
23→    const request = context.switchToHttp().getRequest();
24→    const user = request.user;
25→
26→    if (!user) {
27→      throw new ForbiddenException('No user context');
28→    }
29→
30→    const userRoles: string[] = (user.userRoles || []).map(
31→      (ur: any) => ur.role?.name || ur.roleName,
32→    );
33→
34→    const hasRole = requiredRoles.some((role) => userRoles.includes(role));
35→    if (!hasRole) {
36→      throw new ForbiddenException('Insufficient permissions');
37→    }
38→
39→    return true;
40→  }
41→}
