15→export class User {
16→  @PrimaryGeneratedColumn('uuid')
17→  id: string;
18→
19→  @Column({ type: 'varchar', length: 255, unique: true })
20→  @Index('idx_users_username', { unique: true })
21→  username: string;
22→
23→  @Column({ type: 'text' })
24→  @Exclude()
25→  passwordHash: string;
26→
27→  @Column({ type: 'varchar', length: 255 })
28→  displayName: string;
29→
30→  @Column({ type: 'text', nullable: true })
31→  @Exclude()
32→  governmentId: string | null;
33→
34→  @Column({ type: 'text', nullable: true })
35→  @Exclude()
36→  employeeId: string | null;
37→
38→  @Column({ type: 'timestamptz', nullable: true })
39→  lockedUntil: Date | null;
40→
41→  @Column({ type: 'boolean', default: true })
42→  isActive: boolean;
43→
44→  @CreateDateColumn({ type: 'timestamptz' })
