 6→  Inject,
 7→  Optional,
 8→} from '@nestjs/common';
 9→import { Observable, tap } from 'rxjs';
10→import { getTraceId } from './trace-id.interceptor';
11→
12→export interface IAuditService {
13→  recordEvent(event: {
14→    traceId: string;
15→    actorId?: string;
16→    action: string;
17→    resourceType: string;
18→    resourceId?: string;
19→    changes?: any;
20→    reason?: string;
21→    ipAddress?: string;
22→    metadata?: any;
23→  }): Promise<void>;
24→}
25→
26→@Injectable()
27→export class AuditInterceptor implements NestInterceptor {
28→  constructor(
29→    @Optional() @Inject('AuditService') private readonly auditService?: IAuditService,
30→  ) {}
31→
32→  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
33→    const request = context.switchToHttp().getRequest();
34→    const method = request.method;
35→
36→    // Only audit write operations
37→    if (['GET', 'HEAD', 'OPTIONS'].includes(method)) {
38→      return next.handle();
39→    }
40→
41→    return next.handle().pipe(
42→      tap(async (responseData) => {
43→        if (!this.auditService) return;
44→
45→        try {
46→          const traceId = getTraceId();
47→          const user = request.user;
48→          const path: string = request.route?.path || request.url;
49→
50→          // Derive resource type and action from route
51→          const resourceType = this.extractResourceType(path);
52→          const action = `${resourceType}.${method.toLowerCase()}`;
53→
54→          await this.auditService.recordEvent({
55→            traceId,
56→            actorId: user?.id,
57→            action,
58→            resourceType,
59→            resourceId: request.params?.id,
60→            ipAddress: request.ip,
61→            metadata: {
62→              url: request.url,
63→              method,
64→            },
65→          });
66→        } catch {
67→          // Audit failures must not break the request
68→        }
69→      }),
70→    );
71→  }
72→
73→  private extractResourceType(path: string): string {
74→    const segments = path.replace(/^\/api\/v1\//, '').split('/');
75→    return segments[0] || 'unknown';
76→  }
77→}
