28→    request[TraceIdInterceptor.TRACE_ID_KEY] = traceId;
29→    response.setHeader('X-Trace-Id', traceId);
30→
31→    return new Observable((subscriber) => {
32→      traceStorage.run(traceId, () => {
33→        next.handle().subscribe({
34→          next: (val) => subscriber.next(val),
35→          error: (err) => subscriber.error(err),
36→          complete: () => subscriber.complete(),
37→        });
38→      });
39→    });
40→  }
