 1→import {
 2→  Injectable,
 3→  NestInterceptor,
 4→  ExecutionContext,
 5→  CallHandler,
 6→} from '@nestjs/common';
 7→import { Observable, map } from 'rxjs';
 8→
 9→const EXCLUDED_FIELDS = [
10→  'password_hash',
11→  'passwordHash',
12→  'reset_token_hash',
13→  'resetTokenHash',
14→  'encryptionKey',
15→  'encryption_key',
16→];
17→
18→const MASKED_FIELDS: Record<string, (val: string) => string> = {
19→  government_id: maskLastFour,
20→  governmentId: maskLastFour,
21→  employee_id: maskLastFour,
22→  employeeId: maskLastFour,
23→};
24→
25→function maskLastFour(value: string): string {
26→  if (!value || value.length <= 4) return '****';
27→  return '*'.repeat(value.length - 4) + value.slice(-4);
28→}
29→
30→function maskObject(obj: any): any {
31→  if (obj === null || obj === undefined) return obj;
32→  if (Array.isArray(obj)) return obj.map(maskObject);
33→  if (typeof obj !== 'object') return obj;
34→  if (obj instanceof Date) return obj;
35→
36→  const result: any = {};
37→  for (const [key, value] of Object.entries(obj)) {
38→    if (EXCLUDED_FIELDS.includes(key)) {
39→      continue; // strip entirely
40→    }
41→    if (MASKED_FIELDS[key] && typeof value === 'string') {
42→      result[key] = MASKED_FIELDS[key](value);
43→    } else if (typeof value === 'object') {
44→      result[key] = maskObject(value);
45→    } else {
46→      result[key] = value;
47→    }
48→  }
49→  return result;
50→}
51→
52→@Injectable()
53→export class MaskingInterceptor implements NestInterceptor {
54→  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
55→    return next.handle().pipe(map((data) => maskObject(data)));
56→  }
57→}
58→
59→export { maskObject, maskLastFour };
