 21→
 22→@Injectable()
 23→export class ReservationsService {
 24→  constructor(
 25→    @InjectRepository(Reservation)
 26→    private reservationRepo: Repository<Reservation>,
 27→    @InjectRepository(Offering)
 28→    private offeringRepo: Repository<Offering>,
 29→    private idempotencyService: IdempotencyService,
 30→    private auditService: AuditService,
 31→    private config: AppConfigService,
 32→    private dataSource: DataSource,
 33→  ) {}
 34→
 35→  async createReservation(
 36→    offeringId: string,
 37→    userId: string,
 38→    idempotencyKey: string,
 39→  ) {
 40→    // Check idempotency
 41→    const idempCheck = await this.idempotencyService.check(
 42→      idempotencyKey,
 43→      'reservations.create',
 44→      userId,
 45→    );
 46→    if (idempCheck.isDuplicate) {
 47→      return idempCheck.storedResponse!.body;
 48→    }
 49→
 50→    return this.dataSource.transaction(async (manager) => {
 51→      // Lock the offering row for update
 52→      const offering = await manager
 53→        .createQueryBuilder(Offering, 'o')
 54→        .setLock('pessimistic_write')
 55→        .where('o.id = :id', { id: offeringId })
 56→        .getOne();
 57→
 58→      if (!offering) {
 59→        throw new NotFoundException('Offering not found');
 60→      }
 61→
 62→      if (!offering.isWindowOpen()) {
 63→        throw new BadRequestException('Enrollment window is not open');
 64→      }
 65→
 66→      // Check for existing active reservation or enrollment
 67→      const existingReservation = await manager.findOne(Reservation, {
 68→        where: {
 69→          offeringId,
 70→          userId,
 71→          status: ReservationStatus.HELD,
 72→        },
 73→      });
 74→      if (existingReservation) {
 75→        throw new ConflictException(
 76→          'You already have an active reservation for this offering',
 77→        );
 78→      }
 79→
 80→      const existingEnrollment = await manager
 81→        .createQueryBuilder(Enrollment, 'e')
 82→        .where('e.offeringId = :offeringId', { offeringId })
 83→        .andWhere('e.userId = :userId', { userId })
 84→        .andWhere("e.status != :canceled", { canceled: EnrollmentStatus.CANCELED })
 85→        .getOne();
 86→      if (existingEnrollment) {
 87→        throw new ConflictException(
 88→          'You are already enrolled in this offering',
 89→        );
 90→      }
 91→
 92→      const now = new Date();
 93→      const expiresAt = new Date(
 94→        now.getTime() + this.config.reservationHoldMinutes * 60 * 1000,
 95→      );
 96→
 97→      if (offering.seatsAvailable > 0) {
 98→        // Decrement seats atomically
 99→        await manager
100→          .createQueryBuilder()
101→          .update(Offering)
102→          .set({ seatsAvailable: () => '"seatsAvailable" - 1' })
103→          .where('id = :id AND "seatsAvailable" > 0', { id: offeringId })
104→          .execute();
105→
106→        const reservation = manager.create(Reservation, {
107→          offeringId,
108→          userId,
109→          status: ReservationStatus.HELD,
110→          heldAt: now,
111→          expiresAt,
112→          idempotencyKey,
113→        });
114→        const saved = await manager.save(reservation);
115→
116→        // Record state transition
117→        await manager.save(
118→          manager.create(EnrollmentStateTransition, {
119→            reservationId: saved.id,
120→            fromState: 'NONE',
121→            toState: 'HELD',
122→            actorId: userId,
123→            traceId: getTraceId(),
124→            reason: 'Seat reserved',
125→          }),
126→        );
127→
128→        await this.auditService.recordEvent({
129→          action: 'reservation.create',
130→          resourceType: 'reservations',
131→          resourceId: saved.id,
132→          actorId: userId,
133→        });
134→
135→        const response = {
136→          id: saved.id,
137→          offeringId: saved.offeringId,
138→          status: saved.status,
139→          heldAt: saved.heldAt,
140→          expiresAt: saved.expiresAt,
141→        };
142→
143→        await this.idempotencyService.store(
144→          idempotencyKey,
145→          'reservations.create',
146→          userId,
147→          201,
148→          response,
149→        );
150→
151→        return response;
152→      } else if (offering.waitlistEnabled) {
153→        // Create waitlisted enrollment directly
154→        const enrollment = manager.create(Enrollment, {
155→          offeringId,
156→          userId,
157→          status: EnrollmentStatus.WAITLISTED,
158→          waitlistedAt: now,
159→          idempotencyKey,
160→        });
161→        const saved = await manager.save(enrollment);
162→
163→        await manager.save(
164→          manager.create(EnrollmentStateTransition, {
165→            enrollmentId: saved.id,
166→            fromState: 'NONE',
167→            toState: 'WAITLISTED',
168→            actorId: userId,
169→            traceId: getTraceId(),
170→            reason: 'No seats available, added to waitlist',
171→          }),
172→        );
173→
174→        await this.auditService.recordEvent({
175→          action: 'enrollment.waitlisted',
176→          resourceType: 'enrollments',
177→          resourceId: saved.id,
178→          actorId: userId,
179→        });
180→
181→        const response = {
182→          id: saved.id,
183→          offeringId: saved.offeringId,
184→          status: saved.status,
185→          waitlistedAt: saved.waitlistedAt,
186→        };
187→
188→        await this.idempotencyService.store(
189→          idempotencyKey,
190→          'reservations.create',
191→          userId,
192→          201,
193→          response,
194→        );
195→
196→        return response;
197→      } else {
198→        throw new HttpException(
199→          'No seats available and waitlist is not enabled',
200→          HttpStatus.UNPROCESSABLE_ENTITY,
201→        );
202→      }
203→    });
204→  }
