206→  async releaseReservation(
207→    reservationId: string,
208→    userId: string,
209→    idempotencyKey: string,
210→  ): Promise<void> {
211→    const idempCheck = await this.idempotencyService.check(
212→      idempotencyKey,
213→      'reservations.release',
214→      userId,
215→    );
216→    if (idempCheck.isDuplicate) return;
217→
218→    await this.dataSource.transaction(async (manager) => {
219→      const reservation = await manager.findOne(Reservation, {
220→        where: { id: reservationId },
221→      });
222→      if (!reservation) throw new NotFoundException('Reservation not found');
223→      if (reservation.status !== ReservationStatus.HELD) {
