225→      }
226→
227→      reservation.status = ReservationStatus.RELEASED;
228→      reservation.releasedAt = new Date();
229→      await manager.save(reservation);
230→
231→      // Return seat
232→      await manager
233→        .createQueryBuilder()
234→        .update(Offering)
235→        .set({ seatsAvailable: () => '"seatsAvailable" + 1' })
236→        .where('id = :id', { id: reservation.offeringId })
237→        .execute();
238→
239→      await manager.save(
240→        manager.create(EnrollmentStateTransition, {
241→          reservationId: reservation.id,
242→          fromState: 'HELD',
243→          toState: 'RELEASED',
244→          actorId: userId,
245→          traceId: getTraceId(),
246→          reason: 'Manual release',
247→        }),
248→      );
249→
250→      await this.auditService.recordEvent({
251→        action: 'reservation.release',
252→        resourceType: 'reservations',
253→        resourceId: reservationId,
254→        actorId: userId,
255→      });
256→    });
257→
258→    await this.idempotencyService.store(
259→      idempotencyKey,
260→      'reservations.release',
261→      userId,
262→      204,
263→      null,
264→    );
265→  }
