273→  /**
274→   * Auto-release expired reservations. Called by scheduled job.
275→   */
276→  async releaseExpiredReservations(): Promise<number> {
277→    const now = new Date();
278→
279→    // Use FOR UPDATE SKIP LOCKED to prevent double-processing
280→    const expired = await this.dataSource
281→      .createQueryBuilder(Reservation, 'r')
282→      .setLock('pessimistic_write_or_fail')
283→      .where('r.status = :status', { status: ReservationStatus.HELD })
284→      .andWhere('r.expiresAt < :now', { now })
285→      .getMany()
286→      .catch(() => [] as Reservation[]); // SKIP LOCKED not directly available, fallback
287→
288→    let released = 0;
289→    for (const reservation of expired) {
290→      try {
291→        await this.dataSource.transaction(async (manager) => {
292→          // Re-check status inside transaction
293→          const current = await manager
294→            .createQueryBuilder(Reservation, 'r')
295→            .setLock('pessimistic_write')
296→            .where('r.id = :id AND r.status = :status', {
297→              id: reservation.id,
298→              status: ReservationStatus.HELD,
299→            })
300→            .getOne();
301→
302→          if (!current) return;
303→
304→          current.status = ReservationStatus.RELEASED;
305→          current.releasedAt = now;
306→          await manager.save(current);
307→
308→          await manager
309→            .createQueryBuilder()
310→            .update(Offering)
311→            .set({ seatsAvailable: () => '"seatsAvailable" + 1' })
312→            .where('id = :id', { id: current.offeringId })
313→            .execute();
314→
315→          await manager.save(
316→            manager.create(EnrollmentStateTransition, {
317→              reservationId: current.id,
318→              fromState: 'HELD',
319→              toState: 'RELEASED',
320→              actorId: SYSTEM_ACTOR_ID,
321→              traceId: getTraceId(),
322→              reason: 'Auto-release: hold expired',
323→            }),
324→          );
325→
326→          await this.auditService.recordEvent({
327→            action: 'reservation.auto_release',
328→            resourceType: 'reservations',
329→            resourceId: current.id,
330→            reason: 'Hold expired',
331→          });
332→
333→          released++;
334→        });
335→      } catch {
336→        // Individual failures don't block others
337→      }
338→    }
339→
340→    return released;
341→  }
342→}
