 1→import { Injectable } from '@nestjs/common';
 2→import { createCipheriv, createDecipheriv, randomBytes } from 'crypto';
 3→import { AppConfigService } from '../config/config.service';
 4→
 5→@Injectable()
 6→export class EncryptionService {
 7→  private readonly algorithm = 'aes-256-gcm';
 8→  private readonly ivLength = 12;
 9→  private readonly authTagLength = 16;
10→
11→  constructor(private config: AppConfigService) {}
12→
13→  encrypt(plaintext: string): string {
14→    const key = this.getKeyBuffer();
15→    const iv = randomBytes(this.ivLength);
16→    const cipher = createCipheriv(this.algorithm, key, iv, {
17→      authTagLength: this.authTagLength,
18→    });
19→
20→    let encrypted = cipher.update(plaintext, 'utf8', 'base64');
21→    encrypted += cipher.final('base64');
22→    const authTag = cipher.getAuthTag();
23→
24→    return `${iv.toString('base64')}:${authTag.toString('base64')}:${encrypted}`;
25→  }
26→
27→  decrypt(ciphertext: string): string {
28→    try {
29→      return this.decryptWithKey(ciphertext, this.getKeyBuffer());
30→    } catch {
31→      const prevKey = this.getPreviousKeyBuffer();
32→      if (prevKey) {
33→        return this.decryptWithKey(ciphertext, prevKey);
34→      }
35→      throw new Error('Decryption failed');
36→    }
37→  }
38→
39→  private decryptWithKey(ciphertext: string, key: Buffer): string {
40→    const parts = ciphertext.split(':');
41→    if (parts.length !== 3) {
42→      throw new Error('Invalid ciphertext format');
43→    }
44→
45→    const iv = Buffer.from(parts[0], 'base64');
46→    const authTag = Buffer.from(parts[1], 'base64');
47→    const encrypted = parts[2];
48→
49→    const decipher = createDecipheriv(this.algorithm, key, iv, {
50→      authTagLength: this.authTagLength,
51→    });
52→    decipher.setAuthTag(authTag);
53→
54→    let decrypted = decipher.update(encrypted, 'base64', 'utf8');
55→    decrypted += decipher.final('utf8');
56→    return decrypted;
57→  }
58→
59→  private getKeyBuffer(): Buffer {
60→    const hexKey = this.config.encryptionKey;
61→    if (!hexKey || hexKey.length !== 64) {
62→      throw new Error(
63→        'ENCRYPTION_KEY must be a 64-character hex string (32 bytes)',
64→      );
65→    }
66→    return Buffer.from(hexKey, 'hex');
67→  }
68→
69→  private getPreviousKeyBuffer(): Buffer | null {
70→    const hexKey = this.config.encryptionKeyPrevious;
71→    if (!hexKey || hexKey.length !== 64) return null;
72→    return Buffer.from(hexKey, 'hex');
73→  }
74→}
