  1→import {
  2→  Injectable,
  3→  NotFoundException,
  4→  BadRequestException,
  5→  ConflictException,
  6→  HttpException,
  7→  HttpStatus,
  8→} from '@nestjs/common';
  9→import { InjectRepository } from '@nestjs/typeorm';
 10→import { Repository, DataSource, Not } from 'typeorm';
 11→import { Enrollment, EnrollmentStatus } from './enrollment.entity';
 12→import { EnrollmentStateTransition } from './enrollment-state-transition.entity';
 13→import { Reservation, ReservationStatus } from '../reservations/reservation.entity';
 14→import { Offering } from '../offerings/offering.entity';
