 18→
 19→@Injectable()
 20→export class EnrollmentsService {
 21→  constructor(
 22→    @InjectRepository(Enrollment)
 23→    private enrollmentRepo: Repository<Enrollment>,
 24→    @InjectRepository(EnrollmentStateTransition)
 25→    private transitionRepo: Repository<EnrollmentStateTransition>,
 26→    private idempotencyService: IdempotencyService,
 27→    private auditService: AuditService,
 28→    private dataSource: DataSource,
 29→  ) {}
 30→
 31→  async confirmReservation(
 32→    reservationId: string,
 33→    userId: string,
 34→    idempotencyKey: string,
 35→  ) {
 36→    const idempCheck = await this.idempotencyService.check(
 37→      idempotencyKey,
 38→      'enrollments.confirm',
 39→      userId,
 40→    );
 41→    if (idempCheck.isDuplicate) {
 42→      return idempCheck.storedResponse!.body;
 43→    }
 44→
 45→    return this.dataSource.transaction(async (manager) => {
 46→      const reservation = await manager
 47→        .createQueryBuilder(Reservation, 'r')
 48→        .setLock('pessimistic_write')
 49→        .where('r.id = :id', { id: reservationId })
 50→        .getOne();
 51→
 52→      if (!reservation) {
 53→        throw new NotFoundException('Reservation not found');
 54→      }
 55→
 56→      if (reservation.userId !== userId) {
 57→        throw new BadRequestException('Reservation does not belong to you');
 58→      }
 59→
 60→      if (reservation.status !== ReservationStatus.HELD) {
 61→        throw new BadRequestException('Reservation is not in HELD status');
 62→      }
 63→
 64→      if (reservation.expiresAt < new Date()) {
 65→        throw new HttpException(
 66→          'Reservation has expired',
 67→          HttpStatus.GONE,
 68→        );
 69→      }
 70→
 71→      // Check for duplicate enrollment
 72→      const existingEnrollment = await manager
 73→        .createQueryBuilder(Enrollment, 'e')
 74→        .where('e.offeringId = :offeringId', {
 75→          offeringId: reservation.offeringId,
 76→        })
 77→        .andWhere('e.userId = :userId', { userId })
 78→        .andWhere("e.status != :canceled", {
 79→          canceled: EnrollmentStatus.CANCELED,
 80→        })
 81→        .getOne();
 82→
 83→      if (existingEnrollment) {
 84→        throw new ConflictException(
 85→          'You are already enrolled in this offering',
 86→        );
 87→      }
 88→
 89→      // Convert reservation
 90→      reservation.status = ReservationStatus.CONVERTED;
 91→      await manager.save(reservation);
 92→
 93→      // Create enrollment
 94→      const enrollment = manager.create(Enrollment, {
 95→        offeringId: reservation.offeringId,
 96→        userId,
 97→        reservationId,
 98→        status: EnrollmentStatus.CONFIRMED,
 99→        confirmedAt: new Date(),
100→        idempotencyKey,
101→      });
102→      const saved = await manager.save(enrollment);
103→
104→      // Record transitions
105→      await manager.save(
106→        manager.create(EnrollmentStateTransition, {
107→          reservationId,
108→          fromState: 'HELD',
109→          toState: 'CONVERTED',
110→          actorId: userId,
111→          traceId: getTraceId(),
112→          reason: 'Reservation confirmed',
113→        }),
114→      );
115→      await manager.save(
116→        manager.create(EnrollmentStateTransition, {
117→          enrollmentId: saved.id,
118→          fromState: 'NONE',
119→          toState: 'CONFIRMED',
120→          actorId: userId,
121→          traceId: getTraceId(),
122→          reason: 'Enrollment confirmed from reservation',
123→        }),
124→      );
125→
126→      await this.auditService.recordEvent({
127→        action: 'enrollment.confirm',
128→        resourceType: 'enrollments',
129→        resourceId: saved.id,
130→        actorId: userId,
131→      });
132→
133→      const response = {
134→        id: saved.id,
135→        offeringId: saved.offeringId,
136→        status: saved.status,
137→        confirmedAt: saved.confirmedAt,
138→      };
139→
140→      await this.idempotencyService.store(
141→        idempotencyKey,
142→        'enrollments.confirm',
143→        userId,
144→        201,
145→        response,
146→      );
147→
148→      return response;
149→    });
150→  }
151→
152→  async cancelEnrollment(
153→    enrollmentId: string,
154→    userId: string,
155→    idempotencyKey: string,
156→    reason?: string,
157→  ) {
158→    const idempCheck = await this.idempotencyService.check(
159→      idempotencyKey,
160→      'enrollments.cancel',
161→      userId,
162→    );
163→    if (idempCheck.isDuplicate) {
164→      return idempCheck.storedResponse!.body;
165→    }
166→
167→    return this.dataSource.transaction(async (manager) => {
168→      const enrollment = await manager
169→        .createQueryBuilder(Enrollment, 'e')
170→        .setLock('pessimistic_write')
171→        .where('e.id = :id', { id: enrollmentId })
172→        .getOne();
173→
174→      if (!enrollment) {
175→        throw new NotFoundException('Enrollment not found');
176→      }
177→
178→      if (enrollment.status === EnrollmentStatus.CANCELED) {
179→        throw new BadRequestException('Enrollment is already canceled');
180→      }
181→
182→      const previousStatus = enrollment.status;
183→      enrollment.status = EnrollmentStatus.CANCELED;
184→      enrollment.canceledAt = new Date();
185→      enrollment.cancelReason = reason || null;
186→      await manager.save(enrollment);
187→
188→      // Return seat if was confirmed
189→      if (previousStatus === EnrollmentStatus.CONFIRMED) {
190→        await manager
191→          .createQueryBuilder()
192→          .update(Offering)
193→          .set({ seatsAvailable: () => '"seatsAvailable" + 1' })
194→          .where('id = :id', { id: enrollment.offeringId })
195→          .execute();
196→      }
197→
198→      await manager.save(
199→        manager.create(EnrollmentStateTransition, {
200→          enrollmentId: enrollment.id,
201→          fromState: previousStatus,
202→          toState: 'CANCELED',
203→          actorId: userId,
204→          traceId: getTraceId(),
205→          reason: reason || 'Enrollment canceled',
206→        }),
207→      );
208→
209→      await this.auditService.recordEvent({
210→        action: 'enrollment.cancel',
211→        resourceType: 'enrollments',
212→        resourceId: enrollmentId,
213→        actorId: userId,
214→      });
215→
216→      const response = {
217→        id: enrollment.id,
218→        offeringId: enrollment.offeringId,
219→        status: enrollment.status,
220→        canceledAt: enrollment.canceledAt,
221→      };
222→
223→      await this.idempotencyService.store(
224→        idempotencyKey,
225→        'enrollments.cancel',
226→        userId,
227→        200,
228→        response,
229→      );
230→
231→      return response;
232→    });
233→  }
234→
235→  async approveEnrollment(
236→    enrollmentId: string,
237→    actorId: string,
238→    reason?: string,
239→  ) {
240→    return this.dataSource.transaction(async (manager) => {
241→      const enrollment = await manager
242→        .createQueryBuilder(Enrollment, 'e')
243→        .setLock('pessimistic_write')
244→        .where('e.id = :id', { id: enrollmentId })
245→        .getOne();
246→
247→      if (!enrollment) throw new NotFoundException('Enrollment not found');
248→      if (enrollment.status !== EnrollmentStatus.WAITLISTED) {
249→        throw new BadRequestException('Can only approve waitlisted enrollments');
250→      }
251→
252→      enrollment.status = EnrollmentStatus.APPROVED;
253→      enrollment.approvedAt = new Date();
254→      await manager.save(enrollment);
255→
256→      await manager.save(
257→        manager.create(EnrollmentStateTransition, {
258→          enrollmentId: enrollment.id,
259→          fromState: 'WAITLISTED',
260→          toState: 'APPROVED',
261→          actorId,
262→          traceId: getTraceId(),
263→          reason: reason || 'Enrollment approved',
264→        }),
265→      );
266→
267→      await this.auditService.recordEvent({
268→        action: 'enrollment.approve',
269→        resourceType: 'enrollments',
270→        resourceId: enrollmentId,
271→        actorId,
272→      });
273→
274→      return enrollment;
275→    });
276→  }
277→
278→  async findAll(query: {
279→    page?: number;
280→    pageSize?: number;
281→    offeringId?: string;
282→    status?: string;
283→    userId?: string;
284→  }) {
285→    const page = query.page || 1;
286→    const pageSize = Math.min(query.pageSize || 20, 100);
287→
288→    const qb = this.enrollmentRepo.createQueryBuilder('e');
289→    if (query.offeringId) qb.andWhere('e.offeringId = :oid', { oid: query.offeringId });
290→    if (query.status) qb.andWhere('e.status = :status', { status: query.status });
291→    if (query.userId) qb.andWhere('e.userId = :uid', { uid: query.userId });
292→
293→    qb.orderBy('e.createdAt', 'DESC');
294→    qb.skip((page - 1) * pageSize).take(pageSize);
295→
296→    const [items, total] = await qb.getManyAndCount();
297→    return { items, total, page, pageSize };
298→  }
299→
300→  async findById(id: string): Promise<Enrollment & { transitions?: EnrollmentStateTransition[] }> {
301→    const enrollment = await this.enrollmentRepo.findOne({ where: { id } });
302→    if (!enrollment) throw new NotFoundException('Enrollment not found');
303→
304→    const transitions = await this.transitionRepo.find({
305→      where: { enrollmentId: id },
306→      order: { timestamp: 'ASC' },
307→    });
308→
309→    return { ...enrollment, transitions };
310→  }
311→
312→  /**
313→   * Promote next waitlisted user for an offering. Called by job.
314→   */
315→  async promoteNextWaitlisted(offeringId: string): Promise<boolean> {
316→    return this.dataSource.transaction(async (manager) => {
317→      const offering = await manager
318→        .createQueryBuilder(Offering, 'o')
319→        .setLock('pessimistic_write')
320→        .where('o.id = :id', { id: offeringId })
321→        .getOne();
322→
323→      if (!offering || offering.seatsAvailable <= 0) return false;
324→
325→      const next = await manager
326→        .createQueryBuilder(Enrollment, 'e')
327→        .where('e.offeringId = :oid AND e.status = :status', {
328→          oid: offeringId,
329→          status: EnrollmentStatus.WAITLISTED,
330→        })
331→        .orderBy('e.waitlistedAt', 'ASC')
332→        .getOne();
333→
334→      if (!next) return false;
335→
336→      if (offering.requiresApproval) {
337→        next.status = EnrollmentStatus.APPROVED;
338→        next.approvedAt = new Date();
339→      } else {
340→        next.status = EnrollmentStatus.CONFIRMED;
341→        next.confirmedAt = new Date();
342→        // Decrement seat
343→        await manager
344→          .createQueryBuilder()
345→          .update(Offering)
346→          .set({ seatsAvailable: () => '"seatsAvailable" - 1' })
347→          .where('id = :id', { id: offeringId })
348→          .execute();
349→      }
350→      await manager.save(next);
351→
352→      await manager.save(
353→        manager.create(EnrollmentStateTransition, {
354→          enrollmentId: next.id,
355→          fromState: 'WAITLISTED',
356→          toState: next.status,
357→          actorId: '00000000-0000-0000-0000-000000000000',
358→          traceId: getTraceId(),
359→          reason: 'Auto-promoted from waitlist',
360→        }),
361→      );
362→
363→      return true;
364→    });
365→  }
366→}
