 7→import { Offering } from '../offerings/offering.entity';
 8→import { v4 as uuidv4 } from 'uuid';
 9→
10→@Injectable()
11→export class ReservationExpiryJob {
12→  private readonly logger = new Logger(ReservationExpiryJob.name);
13→
14→  constructor(
15→    private reservationsService: ReservationsService,
16→    private enrollmentsService: EnrollmentsService,
17→    @InjectRepository(Offering)
18→    private offeringRepo: Repository<Offering>,
19→  ) {}
20→
21→  @Cron('*/1 * * * *') // Every minute
22→  async handleExpiredReservations(): Promise<void> {
23→    const traceId = uuidv4();
24→    this.logger.log(`[${traceId}] Running reservation expiry job`);
25→
26→    try {
27→      const released =
28→        await this.reservationsService.releaseExpiredReservations();
29→      this.logger.log(`[${traceId}] Released ${released} expired reservations`);
30→
31→      // Promote waitlisted users for offerings that freed seats
32→      if (released > 0) {
33→        await this.promoteWaitlistedUsers();
34→      }
35→    } catch (err) {
36→      this.logger.error(
37→        `[${traceId}] Reservation expiry job failed: ${err}`,
38→      );
39→    }
40→  }
41→
42→  @Cron('*/5 * * * *') // Every 5 minutes — safety sweep
43→  async handleWaitlistPromotion(): Promise<void> {
44→    await this.promoteWaitlistedUsers();
45→  }
46→
47→  private async promoteWaitlistedUsers(): Promise<void> {
48→    const offerings = await this.offeringRepo.find({
49→      where: { waitlistEnabled: true },
50→    });
51→
52→    for (const offering of offerings) {
53→      if (offering.seatsAvailable > 0) {
54→        try {
55→          let promoted = true;
56→          while (promoted && offering.seatsAvailable > 0) {
57→            promoted =
58→              await this.enrollmentsService.promoteNextWaitlisted(offering.id);
59→            if (promoted) {
60→              offering.seatsAvailable--;
61→            }
62→          }
63→        } catch {
64→          // Continue with other offerings
65→        }
66→      }
67→    }
68→  }
69→}
