10→
11→const MAX_RETRIES = 3;
12→
13→@Injectable()
14→export class ContentParsingJob {
15→  private readonly logger = new Logger(ContentParsingJob.name);
16→
17→  constructor(
18→    @InjectRepository(ContentAssetVersion)
19→    private versionRepo: Repository<ContentAssetVersion>,
20→    private parsingService: ParsingService,
21→    private duplicateDetection: DuplicateDetectionService,
22→    private filesService: FilesService,
23→    private auditService: AuditService,
24→  ) {}
25→
26→  @Cron('*/5 * * * *') // Every 5 minutes
27→  async parseUnprocessedContent(): Promise<void> {
28→    const pending = await this.versionRepo.find({
29→      where: { parseStatus: 'PENDING' },
30→    });
31→
32→    for (const version of pending) {
33→      try {
34→        this.logger.log(`Parsing version ${version.id}`);
35→
36→        const buffer = this.filesService.getFileBuffer(version.filePath);
37→        const docs = await this.parsingService.parseAndStore(
38→          version.id,
39→          buffer,
40→          version.mimeType,
41→        );
42→
43→        version.parseStatus = 'COMPLETED';
44→        await this.versionRepo.save(version);
45→
46→        // Trigger duplicate detection for each parsed document
47→        for (const doc of docs) {
48→          try {
49→            await this.duplicateDetection.detectExactDuplicates(doc.id);
50→            await this.duplicateDetection.detectNearDuplicates(doc.id);
51→          } catch (err) {
52→            this.logger.warn(
53→              `Duplicate detection failed for doc ${doc.id}: ${err}`,
54→            );
55→          }
56→        }
57→
58→        this.logger.log(
59→          `Parsed version ${version.id}: ${docs.length} documents`,
60→        );
61→      } catch (err) {
62→        version.parseRetries++;
63→        if (version.parseRetries >= MAX_RETRIES) {
64→          version.parseStatus = 'PARSE_ERROR';
65→          await this.auditService.recordEvent({
66→            action: 'content.parse_error',
67→            resourceType: 'content_asset_versions',
68→            resourceId: version.id,
69→            reason: `Parse failed after ${MAX_RETRIES} retries: ${err}`,
70→          });
71→        }
72→        await this.versionRepo.save(version);
73→        this.logger.error(
74→          `Parse failed for version ${version.id} (retry ${version.parseRetries}): ${err}`,
75→        );
76→      }
77→    }
78→  }
79→}
