 1→import { Injectable, NotFoundException } from '@nestjs/common';
 2→import { InjectRepository } from '@nestjs/typeorm';
 3→import { Repository } from 'typeorm';
 4→import { User } from './user.entity';
 5→
 6→@Injectable()
 7→export class UsersService {
 8→  constructor(
 9→    @InjectRepository(User)
10→    private userRepo: Repository<User>,
11→  ) {}
12→
13→  async findById(id: string): Promise<User> {
14→    const user = await this.userRepo.findOne({
15→      where: { id },
16→      relations: ['userRoles', 'userRoles.role'],
17→    });
18→    if (!user) throw new NotFoundException('User not found');
19→    return user;
20→  }
21→
22→  async findAll(query: {
23→    page?: number;
24→    pageSize?: number;
25→    search?: string;
26→    role?: string;
27→    isActive?: boolean;
28→  }) {
29→    const page = query.page || 1;
30→    const pageSize = Math.min(query.pageSize || 20, 100);
31→
32→    const qb = this.userRepo
33→      .createQueryBuilder('u')
34→      .leftJoinAndSelect('u.userRoles', 'ur')
35→      .leftJoinAndSelect('ur.role', 'r');
36→
37→    if (query.search) {
38→      qb.andWhere(
39→        '(u.username ILIKE :search OR u.displayName ILIKE :search)',
40→        { search: `%${query.search}%` },
41→      );
42→    }
43→    if (query.role) {
44→      qb.andWhere('r.name = :role', { role: query.role });
45→    }
46→    if (query.isActive !== undefined) {
47→      qb.andWhere('u.isActive = :isActive', { isActive: query.isActive });
48→    }
49→
50→    qb.orderBy('u.createdAt', 'DESC');
51→    qb.skip((page - 1) * pageSize).take(pageSize);
52→
53→    const [items, total] = await qb.getManyAndCount();
54→    return { items, total, page, pageSize };
55→  }
56→
57→  async updateProfile(
58→    userId: string,
59→    data: { displayName?: string; governmentId?: string; employeeId?: string },
60→  ): Promise<User> {
61→    const user = await this.findById(userId);
62→    if (data.displayName !== undefined) user.displayName = data.displayName;
63→    if (data.governmentId !== undefined) user.governmentId = data.governmentId;
64→    if (data.employeeId !== undefined) user.employeeId = data.employeeId;
65→    return this.userRepo.save(user);
66→  }
