  1→import {
  2→  Injectable,
  3→  NotFoundException,
  4→  BadRequestException,
  5→} from '@nestjs/common';
  6→import { InjectRepository } from '@nestjs/typeorm';
  7→import { Repository } from 'typeorm';
  8→import { Offering } from './offering.entity';
  9→import { AuditService } from '../audit/audit.service';
 10→
 11→@Injectable()
 12→export class OfferingsService {
 13→  constructor(
 14→    @InjectRepository(Offering)
 15→    private offeringRepo: Repository<Offering>,
 16→    private auditService: AuditService,
 17→  ) {}
 18→
 19→  async create(
 20→    data: {
 21→      title: string;
 22→      description?: string;
 23→      assetId?: string;
 24→      seatCapacity: number;
 25→      enrollmentWindowStart: Date;
 26→      enrollmentWindowEnd: Date;
 27→      eligibilityFlags?: Record<string, any>;
 28→      requiresApproval?: boolean;
 29→      waitlistEnabled?: boolean;
 30→    },
 31→    userId: string,
 32→  ): Promise<Offering> {
 33→    if (data.seatCapacity < 1 || data.seatCapacity > 5000) {
 34→      throw new BadRequestException('Seat capacity must be between 1 and 5000');
 35→    }
 36→    if (data.enrollmentWindowEnd <= data.enrollmentWindowStart) {
 37→      throw new BadRequestException(
 38→        'Enrollment window end must be after start',
 39→      );
 40→    }
 41→
 42→    const offering = this.offeringRepo.create({
 43→      title: data.title,
 44→      description: data.description || null,
 45→      assetId: data.assetId || null,
 46→      seatCapacity: data.seatCapacity,
 47→      seatsAvailable: data.seatCapacity,
 48→      enrollmentWindowStart: data.enrollmentWindowStart,
 49→      enrollmentWindowEnd: data.enrollmentWindowEnd,
 50→      eligibilityFlags: data.eligibilityFlags || {},
 51→      requiresApproval: data.requiresApproval ?? false,
 52→      waitlistEnabled: data.waitlistEnabled ?? true,
 53→      createdBy: userId,
 54→    });
 55→
 56→    const saved = await this.offeringRepo.save(offering);
 57→
 58→    await this.auditService.recordEvent({
 59→      action: 'offering.create',
 60→      resourceType: 'offerings',
 61→      resourceId: saved.id,
 62→      actorId: userId,
 63→    });
 64→
 65→    return saved;
 66→  }
 67→
 68→  async findAll(query: {
 69→    page?: number;
 70→    pageSize?: number;
 71→    status?: string;
 72→    search?: string;
 73→  }) {
 74→    const page = query.page || 1;
 75→    const pageSize = Math.min(query.pageSize || 20, 100);
 76→    const now = new Date();
 77→
 78→    const qb = this.offeringRepo.createQueryBuilder('o');
 79→
 80→    if (query.search) {
 81→      qb.andWhere('o.title ILIKE :s', { s: `%${query.search}%` });
 82→    }
 83→    if (query.status === 'open') {
 84→      qb.andWhere('o.enrollmentWindowStart <= :now AND o.enrollmentWindowEnd >= :now', { now });
 85→    } else if (query.status === 'closed') {
 86→      qb.andWhere('o.enrollmentWindowEnd < :now', { now });
 87→    } else if (query.status === 'upcoming') {
 88→      qb.andWhere('o.enrollmentWindowStart > :now', { now });
 89→    }
 90→
 91→    qb.orderBy('o.enrollmentWindowStart', 'DESC');
 92→    qb.skip((page - 1) * pageSize).take(pageSize);
 93→
 94→    const [items, total] = await qb.getManyAndCount();
 95→    return { items, total, page, pageSize };
 96→  }
 97→
 98→  async findById(id: string): Promise<Offering> {
 99→    const offering = await this.offeringRepo.findOne({ where: { id } });
100→    if (!offering) throw new NotFoundException('Offering not found');
101→    return offering;
102→  }
103→
104→  async update(
105→    id: string,
106→    data: Partial<{
107→      title: string;
108→      description: string;
109→      seatCapacity: number;
110→      enrollmentWindowStart: Date;
111→      enrollmentWindowEnd: Date;
112→      eligibilityFlags: Record<string, any>;
113→      requiresApproval: boolean;
114→      waitlistEnabled: boolean;
115→    }>,
116→    userId: string,
117→  ): Promise<Offering> {
118→    const offering = await this.findById(id);
119→
120→    if (data.seatCapacity !== undefined) {
121→      if (data.seatCapacity < 1 || data.seatCapacity > 5000) {
122→        throw new BadRequestException('Seat capacity must be between 1 and 5000');
123→      }
124→      const seatsUsed = offering.seatCapacity - offering.seatsAvailable;
125→      if (data.seatCapacity < seatsUsed) {
126→        throw new BadRequestException(
127→          'Cannot reduce capacity below currently used seats',
128→        );
129→      }
130→      offering.seatsAvailable += data.seatCapacity - offering.seatCapacity;
131→      offering.seatCapacity = data.seatCapacity;
132→    }
133→
134→    Object.assign(offering, {
135→      ...(data.title && { title: data.title }),
136→      ...(data.description !== undefined && { description: data.description }),
137→      ...(data.enrollmentWindowStart && { enrollmentWindowStart: data.enrollmentWindowStart }),
138→      ...(data.enrollmentWindowEnd && { enrollmentWindowEnd: data.enrollmentWindowEnd }),
139→      ...(data.eligibilityFlags && { eligibilityFlags: data.eligibilityFlags }),
140→      ...(data.requiresApproval !== undefined && { requiresApproval: data.requiresApproval }),
141→      ...(data.waitlistEnabled !== undefined && { waitlistEnabled: data.waitlistEnabled }),
142→    });
143→
144→    const saved = await this.offeringRepo.save(offering);
145→
146→    await this.auditService.recordEvent({
147→      action: 'offering.update',
148→      resourceType: 'offerings',
149→      resourceId: id,
150→      actorId: userId,
151→    });
152→
153→    return saved;
154→  }
155→}
