 1→import {
 2→  Injectable,
 3→  NestInterceptor,
 4→  ExecutionContext,
 5→  CallHandler,
 6→} from '@nestjs/common';
 7→import { Observable, tap } from 'rxjs';
 8→import { v4 as uuidv4 } from 'uuid';
 9→import { AsyncLocalStorage } from 'async_hooks';
10→
11→const traceStorage = new AsyncLocalStorage<string>();
12→
13→export function getTraceId(): string {
14→  return traceStorage.getStore() || 'no-trace';
15→}
16→
17→@Injectable()
18→export class TraceIdInterceptor implements NestInterceptor {
19→  static readonly TRACE_ID_KEY = 'traceId';
20→
21→  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
22→    const request = context.switchToHttp().getRequest();
23→    const response = context.switchToHttp().getResponse();
24→
25→    const traceId =
26→      (request.headers['x-trace-id'] as string) || uuidv4();
27→
28→    request[TraceIdInterceptor.TRACE_ID_KEY] = traceId;
29→    response.setHeader('X-Trace-Id', traceId);
30→
31→    return new Observable((subscriber) => {
32→      traceStorage.run(traceId, () => {
33→        next.handle().subscribe({
34→          next: (val) => subscriber.next(val),
35→          error: (err) => subscriber.error(err),
36→          complete: () => subscriber.complete(),
37→        });
38→      });
39→    });
40→  }
41→}
