346→  async getVersions(assetId: string) {
347→    return this.versionRepo.find({
348→      where: { assetId },
349→      order: { createdAt: 'DESC' },
350→    });
351→  }
352→
353→  async getVersion(assetId: string, versionId: string) {
354→    const version = await this.versionRepo.findOne({
355→      where: { id: versionId, assetId },
356→      relations: ['parsedDocuments'],
357→    });
358→    if (!version) throw new NotFoundException('Version not found');
359→    return version;
360→  }
361→
362→  async getDownloadToken(assetId: string, versionId: string, userId: string) {
363→    const version = await this.versionRepo.findOne({
364→      where: { id: versionId, assetId },
365→    });
366→    if (!version) throw new NotFoundException('Version not found');
367→    return this.downloadTokenService.generateToken(assetId, versionId, userId);
368→  }
369→
370→  async getLineage(assetId: string) {
371→    return this.lineageRepo.find({
372→      where: [
373→        { descendantVersionId: assetId },
374→        { ancestorVersionId: assetId },
375→      ],
376→      order: { createdAt: 'DESC' },
377→    });
378→  }
379→
380→  async getDuplicateLinks(assetId: string) {
381→    const currentVersion = await this.versionRepo.findOne({
382→      where: { assetId, isCurrent: true },
383→    });
384→    if (!currentVersion) {
385→      throw new NotFoundException('No current version found for this asset');
386→    }
387→
388→    // Find all parsed documents for the current version
389→    const parsedDocs = await this.dataSource
390→      .createQueryBuilder()
391→      .select('pd.id')
392→      .from('parsed_documents', 'pd')
393→      .where('pd.versionId = :versionId', { versionId: currentVersion.id })
394→      .getRawMany();
395→
396→    if (!parsedDocs.length) {
397→      return [];
398→    }
399→
400→    const docIds = parsedDocs.map((d) => d.pd_id || d.id);
401→
402→    // Query duplicate_links where any of the parsed doc IDs appear as docA or docB
403→    return this.dataSource
404→      .createQueryBuilder()
405→      .select('dl')
406→      .from('duplicate_links', 'dl')
407→      .where('dl.docAId IN (:...docIds) OR dl.docBId IN (:...docIds)', { docIds })
408→      .getRawMany();
409→  }
410→
411→  private bumpVersion(
412→    current: string,
413→    level: 'patch' | 'minor' | 'major',
414→    forceMajor: boolean,
415→  ): string {
416→    const [major, minor, patch] = current.split('.').map(Number);
417→    if (forceMajor) return `${major + 1}.0.0`;
418→    if (level === 'major') return `${major + 1}.0.0`;
419→    if (level === 'minor') return `${major}.${minor + 1}.0`;
420→    return `${major}.${minor}.${patch + 1}`;
421→  }
422→}
