 1→import { Injectable } from '@nestjs/common';
 2→import { AppConfigService } from '../config/config.service';
 3→import { createHash } from 'crypto';
 4→import { mkdirSync, writeFileSync, readFileSync, existsSync, createReadStream } from 'fs';
 5→import { join } from 'path';
 6→import { v4 as uuidv4 } from 'uuid';
 7→import { FileValidatorService } from './file-validator.service';
 8→import { ReadStream } from 'fs';
 9→
10→@Injectable()
11→export class FilesService {
12→  constructor(
13→    private config: AppConfigService,
14→    private validator: FileValidatorService,
15→  ) {}
16→
17→  async storeFile(
18→    file: Express.Multer.File,
19→    assetId: string,
20→    versionId: string,
21→    userId: string,
22→  ): Promise<{
23→    filePath: string;
24→    fileHash: string;
25→    fileSize: number;
26→    mimeType: string;
27→    safeName: string;
28→  }> {
29→    // Validate extension
30→    const ext = this.validator.validateExtension(file.originalname);
31→
32→    // Validate size
33→    this.validator.validateSize(file.size);
34→
35→    // Sanitize filename
36→    const safeName = this.validator.sanitizeFilename(file.originalname);
37→
38→    // Validate magic bytes
39→    this.validator.validateMagicBytes(file.buffer, ext);
40→
41→    // Compute SHA-256 hash
42→    const fileHash = createHash('sha256').update(file.buffer).digest('hex');
43→
44→    // Store file
45→    const dir = join(this.config.fileStoragePath, assetId, versionId);
46→    mkdirSync(dir, { recursive: true });
47→    const filePath = join(dir, safeName);
48→    writeFileSync(filePath, file.buffer);
49→
50→    // Structural validation (after storing, so we can read from disk)
51→    await this.validator.validateStructure(filePath, ext, userId);
52→
53→    const relativePath = `${assetId}/${versionId}/${safeName}`;
54→
55→    return {
56→      filePath: relativePath,
57→      fileHash,
58→      fileSize: file.size,
59→      mimeType: file.mimetype,
60→      safeName,
61→    };
62→  }
63→
64→  getFileStream(relativePath: string): ReadStream {
65→    const fullPath = join(this.config.fileStoragePath, relativePath);
66→    if (!existsSync(fullPath)) {
67→      throw new Error('File not found');
68→    }
69→    return createReadStream(fullPath);
70→  }
71→
72→  getFileBuffer(relativePath: string): Buffer {
73→    const fullPath = join(this.config.fileStoragePath, relativePath);
74→    return readFileSync(fullPath);
75→  }
76→}
