 1→import { Injectable, UnauthorizedException } from '@nestjs/common';
 2→import { AppConfigService } from '../config/config.service';
 3→import { createHmac } from 'crypto';
 4→
 5→interface DownloadTokenPayload {
 6→  assetId: string;
 7→  versionId: string;
 8→  userId: string;
 9→  expiresAt: number; // epoch ms
10→}
11→
12→@Injectable()
13→export class DownloadTokenService {
14→  constructor(private config: AppConfigService) {}
15→
16→  generateToken(
17→    assetId: string,
18→    versionId: string,
19→    userId: string,
20→  ): { downloadToken: string; expiresAt: Date } {
21→    const expiresAt = Date.now() + this.config.downloadTokenExpiryMinutes * 60 * 1000;
22→
23→    const payload: DownloadTokenPayload = {
24→      assetId,
25→      versionId,
26→      userId,
27→      expiresAt,
28→    };
29→
30→    const payloadStr = JSON.stringify(payload);
31→    const payloadB64 = Buffer.from(payloadStr).toString('base64');
32→    const signature = this.sign(payloadB64);
33→
34→    const token = `${payloadB64}.${signature}`;
35→
36→    return {
37→      downloadToken: token,
38→      expiresAt: new Date(expiresAt),
39→    };
40→  }
41→
42→  validateToken(token: string): DownloadTokenPayload {
43→    const parts = token.split('.');
44→    if (parts.length !== 2) {
45→      throw new UnauthorizedException('Invalid download token format');
46→    }
47→
48→    const [payloadB64, signature] = parts;
49→    const expectedSig = this.sign(payloadB64);
50→
51→    if (signature !== expectedSig) {
52→      throw new UnauthorizedException('Invalid download token signature');
53→    }
54→
55→    const payloadStr = Buffer.from(payloadB64, 'base64').toString('utf8');
56→    let payload: DownloadTokenPayload;
57→    try {
58→      payload = JSON.parse(payloadStr);
59→    } catch {
60→      throw new UnauthorizedException('Invalid download token payload');
61→    }
62→
63→    if (Date.now() > payload.expiresAt) {
64→      throw new UnauthorizedException('Download token has expired');
65→    }
66→
67→    return payload;
68→  }
69→
70→  private sign(data: string): string {
71→    return createHmac('sha256', this.config.downloadTokenSecret)
72→      .update(data)
73→      .digest('base64url');
74→  }
75→}
