  1→import {
  2→  Injectable,
  3→  UnauthorizedException,
  4→  BadRequestException,
  5→  HttpException,
  6→  HttpStatus,
  7→} from '@nestjs/common';
  8→import { InjectRepository } from '@nestjs/typeorm';
  9→import { Repository, MoreThan } from 'typeorm';
 10→import * as bcrypt from 'bcrypt';
 11→import { v4 as uuidv4 } from 'uuid';
 12→import { Session } from './session.entity';
 13→import { LoginAttempt } from './login-attempt.entity';
 14→import { PasswordHistory } from './password-history.entity';
 15→import { CredentialResetToken } from './credential-reset-token.entity';
 16→import { User } from '../users/user.entity';
 17→import { AppConfigService } from '../config/config.service';
 18→import { LockoutService } from './lockout.service';
 19→import {
 20→  validatePasswordComplexity,
 21→  assertPasswordComplexity,
 22→} from '../common/validators/password.validator';
 23→import { AuditService } from '../audit/audit.service';
 24→import { getTraceId } from '../common/interceptors/trace-id.interceptor';
 25→import { createHash } from 'crypto';
 26→
 27→@Injectable()
 28→export class AuthService {
 29→  constructor(
 30→    @InjectRepository(Session)
 31→    private sessionRepo: Repository<Session>,
 32→    @InjectRepository(LoginAttempt)
 33→    private loginAttemptRepo: Repository<LoginAttempt>,
 34→    @InjectRepository(PasswordHistory)
 35→    private passwordHistoryRepo: Repository<PasswordHistory>,
 36→    @InjectRepository(CredentialResetToken)
 37→    private resetTokenRepo: Repository<CredentialResetToken>,
 38→    @InjectRepository(User)
 39→    private userRepo: Repository<User>,
 40→    private config: AppConfigService,
 41→    private lockoutService: LockoutService,
 42→    private auditService: AuditService,
 43→  ) {}
 44→
 45→  async register(data: {
 46→    username: string;
 47→    password: string;
 48→    displayName: string;
 49→  }): Promise<{ id: string; username: string; displayName: string; createdAt: Date }> {
 50→    assertPasswordComplexity(data.password);
 51→
 52→    const existing = await this.userRepo.findOne({
 53→      where: { username: data.username },
 54→    });
 55→    if (existing) {
 56→      throw new HttpException('Username already taken', HttpStatus.CONFLICT);
 57→    }
 58→
 59→    const passwordHash = await bcrypt.hash(
 60→      data.password,
 61→      this.config.bcryptCostFactor,
 62→    );
 63→
 64→    const user = this.userRepo.create({
 65→      username: data.username,
 66→      passwordHash,
 67→      displayName: data.displayName,
 68→      isActive: true,
 69→    });
 70→    const saved = await this.userRepo.save(user);
 71→
 72→    // Store initial password in history
 73→    await this.passwordHistoryRepo.save(
 74→      this.passwordHistoryRepo.create({
 75→        userId: saved.id,
 76→        passwordHash,
 77→      }),
 78→    );
 79→
 80→    await this.auditService.recordEvent({
 81→      action: 'auth.register',
 82→      resourceType: 'users',
 83→      resourceId: saved.id,
 84→      actorId: saved.id,
 85→    });
 86→
 87→    return {
 88→      id: saved.id,
 89→      username: saved.username,
 90→      displayName: saved.displayName,
 91→      createdAt: saved.createdAt,
 92→    };
 93→  }
 94→
 95→  async login(
 96→    username: string,
 97→    password: string,
 98→    ipAddress: string,
 99→    userAgent?: string,
100→  ): Promise<{
101→    token: string;
102→    expiresAt: Date;
103→    user: { id: string; username: string; displayName: string; roles: string[] };
104→  }> {
105→    const user = await this.userRepo.findOne({
106→      where: { username },
107→      relations: ['userRoles', 'userRoles.role'],
108→    });
109→
110→    // Check lockout BEFORE password verification (avoid timing attacks)
111→    if (user) {
112→      const isLocked = await this.lockoutService.isLocked(user.id);
113→      if (isLocked) {
114→        await this.recordLoginAttempt(user.id, ipAddress, false);
115→        throw new HttpException(
116→          'Account is temporarily locked. Please try again later.',
117→          HttpStatus.LOCKED,
118→        );
119→      }
120→    }
121→
122→    if (!user || !user.isActive) {
123→      await this.recordLoginAttempt(null, ipAddress, false);
124→      throw new UnauthorizedException('Invalid credentials');
125→    }
126→
127→    const passwordValid = await bcrypt.compare(password, user.passwordHash);
128→    if (!passwordValid) {
129→      await this.recordLoginAttempt(user.id, ipAddress, false);
130→      await this.lockoutService.checkAndLock(user.id);
131→      throw new UnauthorizedException('Invalid credentials');
132→    }
133→
134→    // Successful login — reset failure counter
135→    await this.recordLoginAttempt(user.id, ipAddress, true);
136→
137→    const token = uuidv4();
138→    const expiresAt = new Date(
139→      Date.now() + this.config.sessionTtlHours * 60 * 60 * 1000,
140→    );
141→
142→    await this.sessionRepo.save(
143→      this.sessionRepo.create({
144→        userId: user.id,
145→        token,
146→        expiresAt,
147→        ipAddress,
148→        userAgent: userAgent || null,
149→      }),
150→    );
151→
152→    await this.auditService.recordEvent({
153→      action: 'auth.login',
154→      resourceType: 'sessions',
155→      actorId: user.id,
156→      ipAddress,
157→    });
158→
159→    const roles = (user.userRoles || []).map((ur) => ur.role?.name).filter(Boolean);
160→
161→    return {
162→      token,
163→      expiresAt,
164→      user: {
165→        id: user.id,
166→        username: user.username,
167→        displayName: user.displayName,
168→        roles: roles as string[],
169→      },
170→    };
171→  }
172→
173→  async logout(token: string): Promise<void> {
174→    await this.sessionRepo.delete({ token });
175→  }
176→
177→  async changePassword(
178→    userId: string,
179→    currentPassword: string,
180→    newPassword: string,
181→  ): Promise<void> {
182→    assertPasswordComplexity(newPassword);
183→
184→    const user = await this.userRepo.findOneOrFail({ where: { id: userId } });
185→
186→    const currentValid = await bcrypt.compare(currentPassword, user.passwordHash);
187→    if (!currentValid) {
188→      throw new UnauthorizedException('Current password is incorrect');
189→    }
190→
191→    // Check password history
192→    await this.checkPasswordHistory(userId, newPassword);
193→
194→    const newHash = await bcrypt.hash(newPassword, this.config.bcryptCostFactor);
195→    user.passwordHash = newHash;
196→    await this.userRepo.save(user);
197→
198→    await this.passwordHistoryRepo.save(
199→      this.passwordHistoryRepo.create({
200→        userId,
201→        passwordHash: newHash,
202→      }),
203→    );
204→
205→    // Invalidate all other sessions
206→    await this.sessionRepo
207→      .createQueryBuilder()
208→      .delete()
209→      .where('userId = :userId', { userId })
210→      .execute();
211→
212→    await this.auditService.recordEvent({
213→      action: 'auth.change_password',
214→      resourceType: 'users',
215→      resourceId: userId,
216→      actorId: userId,
217→    });
218→  }
219→
220→  async adminResetPassword(
221→    adminId: string,
222→    targetUserId: string,
223→  ): Promise<{ resetToken: string; expiresAt: Date }> {
224→    const user = await this.userRepo.findOne({ where: { id: targetUserId } });
225→    if (!user) {
226→      throw new BadRequestException('User not found');
227→    }
228→
229→    const rawToken = uuidv4();
230→    const tokenHash = createHash('sha256').update(rawToken).digest('hex');
231→    const expiresAt = new Date(Date.now() + 60 * 60 * 1000); // 1 hour
232→
233→    await this.resetTokenRepo.save(
234→      this.resetTokenRepo.create({
235→        userId: targetUserId,
236→        tokenHash,
237→        expiresAt,
238→      }),
239→    );
240→
241→    await this.auditService.recordEvent({
242→      action: 'auth.admin_reset_password',
243→      resourceType: 'users',
244→      resourceId: targetUserId,
245→      actorId: adminId,
246→    });
247→
248→    return { resetToken: rawToken, expiresAt };
249→  }
250→
251→  async redeemResetToken(
252→    rawToken: string,
253→    newPassword: string,
254→  ): Promise<void> {
255→    assertPasswordComplexity(newPassword);
256→
257→    const tokenHash = createHash('sha256').update(rawToken).digest('hex');
258→    const resetToken = await this.resetTokenRepo.findOne({
259→      where: {
260→        tokenHash,
261→        consumedAt: undefined as any, // IsNull
262→        expiresAt: MoreThan(new Date()),
263→      },
264→    });
265→
266→    if (!resetToken) {
267→      throw new BadRequestException('Invalid or expired reset token');
268→    }
269→
270→    // Check if token is actually null (not consumed) and not expired
271→    if (resetToken.consumedAt !== null) {
272→      throw new BadRequestException('Reset token has already been used');
273→    }
274→
275→    await this.checkPasswordHistory(resetToken.userId, newPassword);
276→
277→    const newHash = await bcrypt.hash(newPassword, this.config.bcryptCostFactor);
278→
279→    const user = await this.userRepo.findOneOrFail({
280→      where: { id: resetToken.userId },
281→    });
282→    user.passwordHash = newHash;
283→    user.lockedUntil = null; // Unlock on reset
284→    await this.userRepo.save(user);
285→
286→    resetToken.consumedAt = new Date();
287→    await this.resetTokenRepo.save(resetToken);
288→
289→    await this.passwordHistoryRepo.save(
290→      this.passwordHistoryRepo.create({
291→        userId: resetToken.userId,
292→        passwordHash: newHash,
293→      }),
294→    );
295→
296→    // Invalidate all sessions
297→    await this.sessionRepo
298→      .createQueryBuilder()
299→      .delete()
300→      .where('userId = :userId', { userId: resetToken.userId })
301→      .execute();
302→
303→    await this.auditService.recordEvent({
304→      action: 'auth.reset_password_redeemed',
305→      resourceType: 'users',
306→      resourceId: resetToken.userId,
307→    });
308→  }
309→
310→  async getFailedAttemptCount(userId: string): Promise<number> {
311→    const windowStart = new Date(
312→      Date.now() - this.config.lockoutWindowMinutes * 60 * 1000,
313→    );
314→    return this.loginAttemptRepo.count({
315→      where: {
316→        userId,
317→        success: false,
318→        attemptedAt: MoreThan(windowStart),
319→      },
320→    });
321→  }
322→
323→  private async recordLoginAttempt(
324→    userId: string | null,
325→    ipAddress: string,
326→    success: boolean,
327→  ): Promise<void> {
328→    await this.loginAttemptRepo.save(
329→      this.loginAttemptRepo.create({ userId, ipAddress, success }),
330→    );
331→  }
332→
333→  private async checkPasswordHistory(
334→    userId: string,
335→    newPassword: string,
336→  ): Promise<void> {
337→    const history = await this.passwordHistoryRepo.find({
338→      where: { userId },
339→      order: { createdAt: 'DESC' },
340→      take: this.config.passwordHistoryCount,
341→    });
342→
343→    for (const entry of history) {
344→      const matches = await bcrypt.compare(newPassword, entry.passwordHash);
345→      if (matches) {
346→        throw new BadRequestException(
347→          `Password was recently used. Choose a different password.`,
348→        );
349→      }
350→    }
351→  }
352→}
