  1→import { Injectable, HttpException, HttpStatus } from '@nestjs/common';
  2→import { InjectRepository } from '@nestjs/typeorm';
  3→import { Repository, MoreThan } from 'typeorm';
  4→import { IdempotencyKey } from './idempotency-key.entity';
  5→import { AppConfigService } from '../config/config.service';
  6→
  7→export interface IdempotencyResult {
  8→  isDuplicate: boolean;
  9→  storedResponse?: { status: number; body: any };
 10→}
 11→
 12→@Injectable()
 13→export class IdempotencyService {
 14→  constructor(
 15→    @InjectRepository(IdempotencyKey)
 16→    private idempotencyRepo: Repository<IdempotencyKey>,
 17→    private config: AppConfigService,
 18→  ) {}
 19→
 20→  /**
 21→   * Check if an idempotency key has been seen. If so, return the stored response.
 22→   * Uses INSERT ON CONFLICT pattern for atomicity.
 23→   */
 24→  async check(
 25→    key: string,
 26→    endpoint: string,
 27→    userId: string,
 28→  ): Promise<IdempotencyResult> {
 29→    if (!key) {
 30→      throw new HttpException(
 31→        'Idempotency-Key header is required',
 32→        HttpStatus.BAD_REQUEST,
 33→      );
 34→    }
 35→
 36→    const windowStart = new Date(
 37→      Date.now() - this.config.idempotencyWindowHours * 60 * 60 * 1000,
 38→    );
 39→
 40→    const existing = await this.idempotencyRepo.findOne({
 41→      where: {
 42→        key,
 43→        createdAt: MoreThan(windowStart),
 44→      },
 45→    });
 46→
 47→    if (existing) {
 48→      return {
 49→        isDuplicate: true,
 50→        storedResponse: {
 51→          status: existing.responseStatus,
 52→          body: existing.responseBody,
 53→        },
 54→      };
 55→    }
 56→
 57→    return { isDuplicate: false };
 58→  }
 59→
 60→  /**
 61→   * Store the response for an idempotency key after successful processing.
 62→   */
 63→  async store(
 64→    key: string,
 65→    endpoint: string,
 66→    userId: string,
 67→    responseStatus: number,
 68→    responseBody: any,
 69→  ): Promise<void> {
 70→    try {
 71→      await this.idempotencyRepo.save(
 72→        this.idempotencyRepo.create({
 73→          key,
 74→          endpoint,
 75→          userId,
 76→          responseStatus,
 77→          responseBody,
 78→        }),
 79→      );
 80→    } catch (err: any) {
 81→      // Duplicate key — race condition handled gracefully
 82→      if (err.code === '23505') {
 83→        return;
 84→      }
 85→      throw err;
 86→    }
 87→  }
 88→
 89→  /**
 90→   * Purge expired idempotency keys.
 91→   */
 92→  async purgeExpired(): Promise<number> {
 93→    const cutoff = new Date(
 94→      Date.now() - this.config.idempotencyWindowHours * 60 * 60 * 1000,
 95→    );
 96→    const result = await this.idempotencyRepo
 97→      .createQueryBuilder()
 98→      .delete()
 99→      .where('createdAt < :cutoff', { cutoff })
100→      .execute();
101→    return result.affected || 0;
102→  }
103→}
