  1→import {
  2→  Injectable,
  3→  BadRequestException,
  4→  HttpException,
  5→  HttpStatus,
  6→} from '@nestjs/common';
  7→import { AppConfigService } from '../config/config.service';
  8→import { AuditService } from '../audit/audit.service';
  9→import { readFileSync } from 'fs';
 10→
 11→const ALLOWED_EXTENSIONS: Record<string, string[]> = {
 12→  '.epub': ['application/epub+zip'],
 13→  '.pdf': ['application/pdf'],
 14→  '.txt': ['text/plain'],
 15→  '.mp4': ['video/mp4'],
 16→  '.mp3': ['audio/mpeg'],
 17→};
 18→
 19→const MAGIC_BYTES: Record<string, Buffer[]> = {
 20→  '.epub': [Buffer.from([0x50, 0x4b, 0x03, 0x04])], // ZIP (EPUB is ZIP-based)
 21→  '.pdf': [Buffer.from('%PDF', 'ascii')],
 22→  '.mp4': [], // ftyp box — checked by structure
 23→  '.mp3': [
 24→    Buffer.from([0xff, 0xfb]), // MPEG sync
 25→    Buffer.from([0xff, 0xf3]),
 26→    Buffer.from([0xff, 0xf2]),
 27→    Buffer.from('ID3', 'ascii'), // ID3 tag
 28→  ],
 29→};
 30→
 31→// PDF dangerous keywords
 32→const PDF_DANGEROUS_PATTERNS = [
 33→  '/JavaScript',
 34→  '/JS',
 35→  '/Launch',
 36→  '/EmbeddedFile',
 37→  '/OpenAction',
 38→  '/AA',
 39→];
 40→
 41→@Injectable()
 42→export class FileValidatorService {
 43→  constructor(
 44→    private config: AppConfigService,
 45→    private auditService: AuditService,
 46→  ) {}
 47→
 48→  sanitizeFilename(originalName: string): string {
 49→    let name = originalName;
 50→    // Strip path traversal
 51→    name = name.replace(/\.\.\//g, '').replace(/\.\.\\/g, '');
 52→    // Strip null bytes
 53→    name = name.replace(/\0/g, '');
 54→    // Strip control characters
 55→    name = name.replace(/[\x00-\x1f\x7f]/g, '');
 56→    // Replace spaces with underscores
 57→    name = name.replace(/\s+/g, '_');
 58→    // Keep only safe characters
 59→    name = name.replace(/[^a-zA-Z0-9._-]/g, '_');
 60→    // Truncate
 61→    if (name.length > 255) {
 62→      const ext = this.getExtension(name);
 63→      name = name.substring(0, 255 - ext.length) + ext;
 64→    }
 65→    return name || 'unnamed_file';
 66→  }
 67→
 68→  getExtension(filename: string): string {
 69→    const lastDot = filename.lastIndexOf('.');
 70→    return lastDot >= 0 ? filename.substring(lastDot).toLowerCase() : '';
 71→  }
 72→
 73→  validateExtension(filename: string): string {
 74→    const ext = this.getExtension(filename);
 75→    if (!ALLOWED_EXTENSIONS[ext]) {
 76→      throw new HttpException(
 77→        `File type '${ext}' is not allowed. Allowed: ${Object.keys(ALLOWED_EXTENSIONS).join(', ')}`,
 78→        HttpStatus.UNSUPPORTED_MEDIA_TYPE,
 79→      );
 80→    }
 81→    return ext;
 82→  }
 83→
 84→  validateSize(size: number): void {
 85→    if (size > this.config.maxFileSizeBytes) {
 86→      throw new HttpException(
 87→        `File size ${size} exceeds maximum of ${this.config.maxFileSizeBytes} bytes (250 MB)`,
 88→        HttpStatus.PAYLOAD_TOO_LARGE,
 89→      );
 90→    }
 91→  }
 92→
 93→  validateMagicBytes(buffer: Buffer, extension: string): void {
 94→    const expectedMagic = MAGIC_BYTES[extension];
 95→    if (!expectedMagic || expectedMagic.length === 0) return;
 96→
 97→    const header = buffer.subarray(0, 8);
 98→    const matches = expectedMagic.some((magic) =>
 99→      header.subarray(0, magic.length).equals(magic),
100→    );
101→
102→    if (!matches) {
103→      throw new HttpException(
104→        'File content does not match declared file type',
105→        HttpStatus.UNSUPPORTED_MEDIA_TYPE,
106→      );
107→    }
108→  }
109→
110→  async validateStructure(
111→    filePath: string,
112→    extension: string,
113→    userId?: string,
114→  ): Promise<void> {
115→    try {
116→      if (extension === '.pdf') {
117→        await this.validatePdfStructure(filePath);
118→      } else if (extension === '.epub') {
119→        await this.validateEpubStructure(filePath);
120→      }
121→      // MP4/MP3/TXT: no structural validation beyond magic bytes
122→    } catch (err: any) {
123→      await this.auditService.recordEvent({
124→        action: 'file.structural_validation_failed',
125→        resourceType: 'files',
126→        actorId: userId,
127→        reason: err.message,
128→      });
129→      throw new HttpException(
130→        `File failed structural validation: ${err.message}`,
131→        HttpStatus.UNPROCESSABLE_ENTITY,
132→      );
133→    }
134→  }
135→
136→  private async validatePdfStructure(filePath: string): Promise<void> {
137→    const content = readFileSync(filePath, 'ascii');
138→    for (const pattern of PDF_DANGEROUS_PATTERNS) {
139→      if (content.includes(pattern)) {
140→        throw new Error(
141→          `PDF contains potentially dangerous element: ${pattern}`,
142→        );
143→      }
144→    }
145→  }
146→
147→  private async validateEpubStructure(filePath: string): Promise<void> {
148→    // EPUB is a ZIP file. Check for suspicious entries.
149→    // We read the first bytes to verify ZIP structure
150→    const buffer = readFileSync(filePath);
151→    if (buffer.length < 4) {
152→      throw new Error('EPUB file too small to be valid');
153→    }
154→    // Check ZIP magic
155→    if (buffer[0] !== 0x50 || buffer[1] !== 0x4b) {
156→      throw new Error('EPUB file is not a valid ZIP archive');
157→    }
158→    // Check for executable extensions in ZIP entries by scanning for common patterns
159→    const content = buffer.toString('ascii');
160→    const dangerousExts = ['.exe', '.bat', '.cmd', '.sh', '.ps1', '.vbs', '.js'];
161→    for (const ext of dangerousExts) {
162→      // Look for filenames ending in dangerous extensions within the ZIP directory
163→      const pattern = ext + '\x00'; // null-terminated in ZIP
164→      if (content.includes(pattern)) {
165→        throw new Error(`EPUB contains potentially dangerous file type: ${ext}`);
166→      }
167→    }
168→  }
169→}
