  5→import { EnrollmentStatus } from '../../src/enrollments/enrollment.entity';
  6→import { ReservationStatus } from '../../src/reservations/reservation.entity';
  7→
  8→describe('Enrollment Lifecycle', () => {
  9→  describe('Reservation to enrollment flow', () => {
 10→    it('should convert HELD reservation to CONVERTED on confirm', () => {
 11→      const reservation = { status: ReservationStatus.HELD };
 12→      reservation.status = ReservationStatus.CONVERTED;
 13→      expect(reservation.status).toBe('CONVERTED');
 14→    });
 15→
 16→    it('should create CONFIRMED enrollment from converted reservation', () => {
 17→      const enrollment = {
 18→        status: EnrollmentStatus.CONFIRMED,
 19→        confirmedAt: new Date(),
 20→        reservationId: 'res-1',
 21→      };
 22→      expect(enrollment.status).toBe('CONFIRMED');
 23→      expect(enrollment.reservationId).toBeDefined();
 24→      expect(enrollment.confirmedAt).toBeInstanceOf(Date);
 25→    });
 26→  });
 27→
 28→  describe('Waitlist flow', () => {
 29→    it('should create WAITLISTED enrollment when no seats', () => {
 30→      const enrollment = {
 31→        status: EnrollmentStatus.WAITLISTED,
 32→        waitlistedAt: new Date(),
 33→      };
 34→      expect(enrollment.status).toBe('WAITLISTED');
 35→    });
 36→
 37→    it('should move WAITLISTED to APPROVED on approval', () => {
 38→      const enrollment = {
 39→        status: EnrollmentStatus.WAITLISTED as string,
 40→        approvedAt: null as Date | null,
 41→      };
 42→      enrollment.status = EnrollmentStatus.APPROVED;
 43→      enrollment.approvedAt = new Date();
 44→      expect(enrollment.status).toBe('APPROVED');
 45→    });
 46→
 47→    it('should move APPROVED to CONFIRMED on user confirm', () => {
 48→      const enrollment = {
 49→        status: EnrollmentStatus.APPROVED as string,
 50→        confirmedAt: null as Date | null,
 51→      };
 52→      enrollment.status = EnrollmentStatus.CONFIRMED;
 53→      enrollment.confirmedAt = new Date();
 54→      expect(enrollment.status).toBe('CONFIRMED');
 55→    });
 56→  });
 57→
 58→  describe('Cancellation', () => {
 59→    it('should allow canceling CONFIRMED enrollment', () => {
 60→      const enrollment = {
 61→        status: EnrollmentStatus.CONFIRMED as string,
 62→        canceledAt: null as Date | null,
 63→        cancelReason: null as string | null,
 64→      };
 65→      enrollment.status = EnrollmentStatus.CANCELED;
 66→      enrollment.canceledAt = new Date();
 67→      enrollment.cancelReason = 'User request';
 68→      expect(enrollment.status).toBe('CANCELED');
 69→      expect(enrollment.cancelReason).toBe('User request');
 70→    });
 71→
 72→    it('should allow canceling WAITLISTED enrollment', () => {
 73→      const enrollment = { status: EnrollmentStatus.WAITLISTED as string };
 74→      enrollment.status = EnrollmentStatus.CANCELED;
 75→      expect(enrollment.status).toBe('CANCELED');
 76→    });
 77→
 78→    it('should return seat on CONFIRMED cancellation', () => {
 79→      let seatsAvailable = 5;
 80→      const previousStatus = EnrollmentStatus.CONFIRMED;
 81→      if (previousStatus === EnrollmentStatus.CONFIRMED) {
 82→        seatsAvailable++;
 83→      }
 84→      expect(seatsAvailable).toBe(6);
 85→    });
 86→
 87→    it('should NOT return seat on WAITLISTED cancellation', () => {
 88→      let seatsAvailable = 5;
 89→      const previousStatus: string = EnrollmentStatus.WAITLISTED;
 90→      if (previousStatus === EnrollmentStatus.CONFIRMED) {
 91→        seatsAvailable++;
 92→      }
 93→      expect(seatsAvailable).toBe(5);
 94→    });
 95→  });
 96→
 97→  describe('Duplicate enrollment prevention', () => {
 98→    it('should reject if user already has non-canceled enrollment', () => {
 99→      const existingEnrollments = [
100→        { userId: 'u1', offeringId: 'o1', status: EnrollmentStatus.CONFIRMED },
101→      ];
102→      const hasActive = existingEnrollments.some(
103→        (e) =>
104→          e.userId === 'u1' &&
105→          e.offeringId === 'o1' &&
106→          e.status !== EnrollmentStatus.CANCELED,
107→      );
108→      expect(hasActive).toBe(true);
109→    });
110→
111→    it('should allow if previous enrollment was canceled', () => {
112→      const existingEnrollments = [
113→        { userId: 'u1', offeringId: 'o1', status: EnrollmentStatus.CANCELED },
114→      ];
115→      const hasActive = existingEnrollments.some(
116→        (e) =>
117→          e.userId === 'u1' &&
118→          e.offeringId === 'o1' &&
119→          e.status !== EnrollmentStatus.CANCELED,
120→      );
121→      expect(hasActive).toBe(false);
122→    });
123→  });
124→
125→  describe('Enrollment window enforcement', () => {
126→    it('should allow reservation when window is open', () => {
127→      const now = new Date();
128→      const start = new Date(now.getTime() - 60000);
129→      const end = new Date(now.getTime() + 60000);
130→      const isOpen = now >= start && now <= end;
131→      expect(isOpen).toBe(true);
132→    });
133→
134→    it('should reject reservation when window is closed', () => {
135→      const now = new Date();
136→      const start = new Date(now.getTime() - 120000);
137→      const end = new Date(now.getTime() - 60000);
138→      const isOpen = now >= start && now <= end;
139→      expect(isOpen).toBe(false);
140→    });
141→
142→    it('should reject reservation when window has not started', () => {
143→      const now = new Date();
144→      const start = new Date(now.getTime() + 60000);
145→      const end = new Date(now.getTime() + 120000);
146→      const isOpen = now >= start && now <= end;
147→      expect(isOpen).toBe(false);
148→    });
149→  });
150→
151→  describe('Manual approval flow', () => {
152→    it('should require approval when offering has requiresApproval=true', () => {
153→      const offering = { requiresApproval: true, waitlistEnabled: true };
154→      const shouldRequireApproval = offering.requiresApproval;
155→      expect(shouldRequireApproval).toBe(true);
