157→
158→    it('should auto-confirm when requiresApproval=false', () => {
159→      const offering = { requiresApproval: false };
160→      expect(offering.requiresApproval).toBe(false);
161→    });
162→  });
163→
164→  describe('State transition recording', () => {
165→    it('should record actor and timestamp on every transition', () => {
166→      const transition = {
167→        fromState: 'HELD',
168→        toState: 'CONFIRMED',
169→        actorId: 'user-123',
170→        timestamp: new Date(),
171→        reason: 'User confirmed enrollment',
172→        traceId: 'trace-456',
173→      };
174→      expect(transition.actorId).toBeDefined();
175→      expect(transition.timestamp).toBeInstanceOf(Date);
176→      expect(transition.traceId).toBeDefined();
177→      expect(transition.reason).toBeDefined();
178→    });
179→  });
180→
181→  describe('Eligibility enforcement', () => {
182→    it('should check employee_only flag', () => {
183→      const eligibility = { employeeOnly: true, departments: ['engineering'] };
184→      const userIsEmployee = true;
185→      expect(eligibility.employeeOnly && userIsEmployee).toBe(true);
186→    });
